  '/js/chat/useElementSize.js': {
    content: `import { ref, onMounted, onUnmounted } from 'vue';

/**
 * 监听元素尺寸变化
 * @param {Ref<HTMLElement | null>} targetRef - 目标元素 ref
 * @returns {Object} { width: Ref<number>, height: Ref<number> }
 */
export function useElementSize(targetRef) {
  const width = ref(0)
  const height = ref(0)
  let observer = null

  const updateSize = () => {
    const el = targetRef.value
    if (!el) return
    width.value = el.clientWidth
    height.value = el.clientHeight
  }

  onMounted(() => {
    updateSize()
    
    observer = new ResizeObserver(() => {
      updateSize()
    })

    const el = targetRef.value
    if (el) {
      observer.observe(el)
    }
  })

  onUnmounted(() => {
    if (observer) {
      observer.disconnect()
      observer = null
    }
  })

  return { width, height }
}
`,
    contentType: 'application/javascript',
  },
